import redis

class RedisLuaClient:
    def __init__(self, host='localhost', port=6379, db=0):
        self.client = redis.StrictRedis(host=host, port=port, db=db)

    def execute_lua_script(self, lua_script, keys=[], args=[]):
        try:
            # Ensure the script is a string and keys/args are lists
            if not isinstance(lua_script, str):
                raise ValueError("Lua script must be a string.")
            if not isinstance(keys, list) or not isinstance(args, list):
                raise ValueError("Keys and args must be lists.")
            
            # Execute the Lua script
            result = self.client.eval(lua_script, len(keys), *keys, *args)
            return result
        except redis.RedisError as e:
            print(f"Redis error: {e}")
        except Exception as e:
            print(f"Error: {e}")

